import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import api from '../services/api';
import Modal from '../components/Modal';
import AttendanceManagement from '../components/AttendanceManagement';
import './SupervisorDashboard.css';

function SupervisorDashboard() {
    const { user, logout } = useAuth();
    const [company, setCompany] = useState(null);
    const [workers, setWorkers] = useState([]);
    const [reports, setReports] = useState([]);
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState('workers');

    // Modal states
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [modalType, setModalType] = useState(''); // 'worker', 'report'
    const [editingItem, setEditingItem] = useState(null);
    const [formData, setFormData] = useState({});
    const [reportFile, setReportFile] = useState(null);

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        try {
            const [companyRes, workersRes, reportsRes] = await Promise.all([
                api.get('/my-company'),
                api.get('/workers'),
                api.get('/reports')
            ]);

            setCompany(companyRes.data);
            setWorkers(workersRes.data);
            setReports(reportsRes.data);
        } catch (error) {
            console.error('Error fetching data:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleLogout = async () => {
        await logout();
        window.location.href = '/login';
    };

    const getTeamCount = (team) => {
        return workers.filter(w => w.team === team && w.is_active).length;
    };

    // Worker CRUD
    const openWorkerModal = (worker = null) => {
        setModalType('worker');
        setEditingItem(worker);
        setFormData(worker || {
            name: '',
            team: 'operators',
            position: '',
            contact_number: '',
            joining_date: '',
            salary: ''
        });
        setIsModalOpen(true);
    };

    const saveWorker = async (e) => {
        e.preventDefault();
        try {
            const data = { ...formData, company_id: company.id };
            if (editingItem) {
                await api.put(`/workers/${editingItem.id}`, data);
            } else {
                await api.post('/workers', data);
            }
            fetchData();
            setIsModalOpen(false);
        } catch (error) {
            console.error('Worker save error:', error);
            const errorMsg = error.response?.data?.message || error.response?.data?.errors || 'Error saving worker';
            alert(typeof errorMsg === 'object' ? JSON.stringify(errorMsg) : errorMsg);
        }
    };

    const deleteWorker = async (id) => {
        if (window.confirm('Are you sure you want to delete this worker?')) {
            try {
                await api.delete(`/workers/${id}`);
                fetchData();
            } catch (error) {
                alert('Error deleting worker');
            }
        }
    };

    // Report CRUD
    const openReportModal = (report = null) => {
        setModalType('report');
        setEditingItem(report);
        setFormData(report || {
            title: '',
            description: '',
            report_date: new Date().toISOString().split('T')[0]
        });
        setReportFile(null);
        setIsModalOpen(true);
    };

    const saveReport = async (e) => {
        e.preventDefault();
        try {
            const data = new FormData();
            data.append('title', formData.title);
            data.append('description', formData.description || '');
            data.append('report_date', formData.report_date);
            if (reportFile) {
                data.append('file', reportFile);
            }

            if (editingItem) {
                await api.post(`/reports/${editingItem.id}`, data, {
                    headers: { 'Content-Type': 'multipart/form-data' }
                });
            } else {
                await api.post('/reports', data, {
                    headers: { 'Content-Type': 'multipart/form-data' }
                });
            }
            fetchData();
            setIsModalOpen(false);
        } catch (error) {
            alert('Error saving report');
        }
    };

    const deleteReport = async (id) => {
        if (window.confirm('Are you sure you want to delete this report?')) {
            try {
                await api.delete(`/reports/${id}`);
                fetchData();
            } catch (error) {
                alert('Error deleting report');
            }
        }
    };

    if (loading) {
        return <div className="loading">Loading...</div>;
    }

    return (
        <div className="supervisor-dashboard">
            <div className="dashboard-header">
                <div>
                    <h1>Supervisor Dashboard</h1>
                    <p>Welcome, {user?.name}</p>
                    <p className="company-name">{company?.name}</p>
                </div>
                <button onClick={handleLogout} className="logout-btn">Logout</button>
            </div>

            <div className="stats-grid">
                <div className="stat-card">
                    <h3>{workers.length}</h3>
                    <p>Total Workers</p>
                </div>
                <div className="stat-card">
                    <h3>{getTeamCount('operators')}</h3>
                    <p>Operators</p>
                </div>
                <div className="stat-card">
                    <h3>{getTeamCount('helpers')}</h3>
                    <p>Helpers</p>
                </div>
                <div className="stat-card">
                    <h3>{reports.length}</h3>
                    <p>Reports</p>
                </div>
            </div>

            <div className="dashboard-tabs">
                <button 
                    className={activeTab === 'workers' ? 'active' : ''} 
                    onClick={() => setActiveTab('workers')}
                >
                    Workers
                </button>
                <button 
                    className={activeTab === 'reports' ? 'active' : ''} 
                    onClick={() => setActiveTab('reports')}
                >
                    Reports
                </button>
            </div>

            <div className="dashboard-content">
                {activeTab === 'workers' && (
                    <div className="table-container">
                        <div className="section-header">
                            <h2>My Workers</h2>
                            <button className="btn-add" onClick={() => openWorkerModal()}>
                                + Add Worker
                            </button>
                        </div>

                        <div className="team-sections">
                            <div className="team-section">
                                <h3><i className="fas fa-users-cog"></i> Operators ({getTeamCount('operators')})</h3>
                                <div className="workers-grid">
                                    {workers.filter(w => w.team === 'operators').map(worker => (
                                        <div key={worker.id} className="worker-card">
                                            <div className="worker-header">
                                                <div className="worker-avatar">
                                                    <i className="fas fa-user-hard-hat"></i>
                                                </div>
                                                <span className={`status-badge ${worker.is_active ? 'active' : 'inactive'}`}>
                                                    {worker.is_active ? 'Active' : 'Inactive'}
                                                </span>
                                            </div>
                                            <h4>{worker.name}</h4>
                                            <div className="worker-details">
                                                <p>
                                                    <i className="fas fa-briefcase"></i>
                                                    <span><strong>Position:</strong> {worker.position || 'Not specified'}</span>
                                                </p>
                                                <p>
                                                    <i className="fas fa-phone"></i>
                                                    <span><strong>Contact:</strong> {worker.contact_number || 'Not provided'}</span>
                                                </p>
                                                <p>
                                                    <i className="fas fa-calendar"></i>
                                                    <span><strong>Joined:</strong> {worker.joining_date ? new Date(worker.joining_date).toLocaleDateString() : 'N/A'}</span>
                                                </p>
                                            </div>
                                            <div className="worker-actions">
                                                <button className="btn-edit" onClick={() => openWorkerModal(worker)}>
                                                    <i className="fas fa-edit"></i> Edit
                                                </button>
                                                <button className="btn-delete" onClick={() => deleteWorker(worker.id)}>
                                                    <i className="fas fa-trash"></i> Delete
                                                </button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>

                            <div className="team-section">
                                <h3><i className="fas fa-hands-helping"></i> Helpers ({getTeamCount('helpers')})</h3>
                                <div className="workers-grid">
                                    {workers.filter(w => w.team === 'helpers').map(worker => (
                                        <div key={worker.id} className="worker-card">
                                            <div className="worker-header">
                                                <div className="worker-avatar">
                                                    <i className="fas fa-user-hard-hat"></i>
                                                </div>
                                                <span className={`status-badge ${worker.is_active ? 'active' : 'inactive'}`}>
                                                    {worker.is_active ? 'Active' : 'Inactive'}
                                                </span>
                                            </div>
                                            <h4>{worker.name}</h4>
                                            <div className="worker-details">
                                                <p>
                                                    <i className="fas fa-briefcase"></i>
                                                    <span><strong>Position:</strong> {worker.position || 'Not specified'}</span>
                                                </p>
                                                <p>
                                                    <i className="fas fa-phone"></i>
                                                    <span><strong>Contact:</strong> {worker.contact_number || 'Not provided'}</span>
                                                </p>
                                                <p>
                                                    <i className="fas fa-calendar"></i>
                                                    <span><strong>Joined:</strong> {worker.joining_date ? new Date(worker.joining_date).toLocaleDateString() : 'N/A'}</span>
                                                </p>
                                            </div>
                                            <div className="worker-actions">
                                                <button className="btn-edit" onClick={() => openWorkerModal(worker)}>
                                                    <i className="fas fa-edit"></i> Edit
                                                </button>
                                                <button className="btn-delete" onClick={() => deleteWorker(worker.id)}>
                                                    <i className="fas fa-trash"></i> Delete
                                                </button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>

                            <div className="team-section">
                                <h3><i className="fas fa-user-tie"></i> Staff ({getTeamCount('staff')})</h3>
                                <div className="workers-grid">
                                    {workers.filter(w => w.team === 'staff').map(worker => (
                                        <div key={worker.id} className="worker-card">
                                            <div className="worker-header">
                                                <div className="worker-avatar">
                                                    <i className="fas fa-user-hard-hat"></i>
                                                </div>
                                                <span className={`status-badge ${worker.is_active ? 'active' : 'inactive'}`}>
                                                    {worker.is_active ? 'Active' : 'Inactive'}
                                                </span>
                                            </div>
                                            <h4>{worker.name}</h4>
                                            <div className="worker-details">
                                                <p>
                                                    <i className="fas fa-briefcase"></i>
                                                    <span><strong>Position:</strong> {worker.position || 'Not specified'}</span>
                                                </p>
                                                <p>
                                                    <i className="fas fa-phone"></i>
                                                    <span><strong>Contact:</strong> {worker.contact_number || 'Not provided'}</span>
                                                </p>
                                                <p>
                                                    <i className="fas fa-calendar"></i>
                                                    <span><strong>Joined:</strong> {worker.joining_date ? new Date(worker.joining_date).toLocaleDateString() : 'N/A'}</span>
                                                </p>
                                            </div>
                                            <div className="worker-actions">
                                                <button className="btn-edit" onClick={() => openWorkerModal(worker)}>
                                                    <i className="fas fa-edit"></i> Edit
                                                </button>
                                                <button className="btn-delete" onClick={() => deleteWorker(worker.id)}>
                                                    <i className="fas fa-trash"></i> Delete
                                                </button>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {activeTab === 'reports' && (
                    <div className="table-container">
                        <div className="section-header">
                            <h2><i className="fas fa-file-alt"></i> My Reports</h2>
                            <button className="btn-add" onClick={() => openReportModal()}>
                                <i className="fas fa-plus"></i> Add Report
                            </button>
                        </div>
                        {reports.length > 0 ? (
                            <div className="reports-grid">
                                {reports.map(report => (
                                    <div key={report.id} className="report-card">
                                        <div className="report-header">
                                            <div className="report-icon">
                                                <i className="fas fa-file-alt"></i>
                                            </div>
                                            <span className="report-date">
                                                <i className="fas fa-calendar"></i>
                                                {new Date(report.report_date).toLocaleDateString()}
                                            </span>
                                        </div>
                                        <div className="report-body">
                                            <h4>{report.title}</h4>
                                            <p>{report.description || 'No description provided'}</p>
                                            {report.file_path && (
                                                <a 
                                                    href={`http://localhost:8000/storage/${report.file_path}`} 
                                                    target="_blank" 
                                                    rel="noopener noreferrer"
                                                    className="file-link"
                                                >
                                                    <i className="fas fa-paperclip"></i> View Attachment
                                                </a>
                                            )}
                                        </div>
                                        <div className="report-actions">
                                            <button className="btn-delete" onClick={() => deleteReport(report.id)}>
                                                <i className="fas fa-trash"></i> Delete
                                            </button>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        ) : (
                            <div className="empty-state">
                                <i className="fas fa-folder-open"></i>
                                <p>No reports submitted yet</p>
                            </div>
                        )}
                    </div>
                )}
            </div>

            {/* Worker Modal */}
            <Modal 
                isOpen={isModalOpen && modalType === 'worker'} 
                onClose={() => setIsModalOpen(false)}
                title={editingItem ? 'Edit Worker' : 'Add Worker'}
            >
                <form onSubmit={saveWorker}>
                    <div className="form-group">
                        <label>Worker Name *</label>
                        <input
                            type="text"
                            value={formData.name || ''}
                            onChange={(e) => setFormData({...formData, name: e.target.value})}
                            required
                        />
                    </div>
                    <div className="form-group">
                        <label>Team *</label>
                        <select
                            value={formData.team || 'operators'}
                            onChange={(e) => setFormData({...formData, team: e.target.value})}
                            required
                        >
                            <option value="operators">Operators</option>
                            <option value="helpers">Helpers</option>
                            <option value="staff">Staff</option>
                            <option value="other">Other</option>
                        </select>
                    </div>
                    <div className="form-group">
                        <label>Position</label>
                        <input
                            type="text"
                            value={formData.position || ''}
                            onChange={(e) => setFormData({...formData, position: e.target.value})}
                        />
                    </div>
                    <div className="form-group">
                        <label>Contact Number</label>
                        <input
                            type="text"
                            value={formData.contact_number || ''}
                            onChange={(e) => setFormData({...formData, contact_number: e.target.value})}
                        />
                    </div>
                    <div className="form-group">
                        <label>Joining Date</label>
                        <input
                            type="date"
                            value={formData.joining_date || ''}
                            onChange={(e) => setFormData({...formData, joining_date: e.target.value})}
                        />
                    </div>
                    <div className="form-group">
                        <label>Salary</label>
                        <input
                            type="number"
                            value={formData.salary || ''}
                            onChange={(e) => setFormData({...formData, salary: e.target.value})}
                        />
                    </div>
                    <div className="form-actions">
                        <button type="button" className="btn-cancel" onClick={() => setIsModalOpen(false)}>Cancel</button>
                        <button type="submit" className="btn-submit">Save</button>
                    </div>
                </form>
            </Modal>

            {/* Report Modal */}
            <Modal 
                isOpen={isModalOpen && modalType === 'report'} 
                onClose={() => setIsModalOpen(false)}
                title={editingItem ? 'Edit Report' : 'Add Report'}
            >
                <form onSubmit={saveReport}>
                    <div className="form-group">
                        <label>Title *</label>
                        <input
                            type="text"
                            value={formData.title || ''}
                            onChange={(e) => setFormData({...formData, title: e.target.value})}
                            required
                        />
                    </div>
                    <div className="form-group">
                        <label>Description</label>
                        <textarea
                            value={formData.description || ''}
                            onChange={(e) => setFormData({...formData, description: e.target.value})}
                            rows="4"
                        />
                    </div>
                    <div className="form-group">
                        <label>Report Date *</label>
                        <input
                            type="date"
                            value={formData.report_date || ''}
                            onChange={(e) => setFormData({...formData, report_date: e.target.value})}
                            required
                        />
                    </div>
                    <div className="form-group">
                        <label>Upload File</label>
                        <input
                            type="file"
                            onChange={(e) => setReportFile(e.target.files[0])}
                            accept=".pdf,.doc,.docx,.xls,.xlsx"
                        />
                    </div>
                    <div className="form-actions">
                        <button type="button" className="btn-cancel" onClick={() => setIsModalOpen(false)}>Cancel</button>
                        <button type="submit" className="btn-submit">Save</button>
                    </div>
                </form>
            </Modal>
        </div>
    );
}

export default SupervisorDashboard;
